// forgotSubmitHandler.js
import { createFormHandler } from './createFormHandler.js';

export function forgotSubmitHandler({
  formId,
  inputId = 'email',
  buttonId = 'button',
  route,
  redirect,
  theme = 'bulma',
  lengthLimitArray = null,   // { id: [...], max: [...] } or null
  recaptchaAction = 'FORGOT'
}) {
  createFormHandler({
    formId,
    buttonId,
    route,
    redirect,
    theme,
    lengthLimit: lengthLimitArray,
    optionalFields: [inputId],
    recaptchaAction
  });
}


