// createFormHandler.js
import { bindEvent } from '../Utility.js';
import { recaptchaToken } from './recaptchaToken.js';
import { loginSubmission } from './processAll.js';

export function createFormHandler({
  formId,
  buttonId = 'button',
  route,
  redirect,
  theme = 'bulma',
  lengthLimit = null,      // { id: [...], max: [...] } or null
  optionalFields = [],     // ['remember_me', 'captcha'] etc.
  recaptchaAction = 'SUBMIT'
}) {
  const handler = async (e) => {
    e.preventDefault();

    const token = await recaptchaToken(recaptchaAction);

    await loginSubmission({
      formId,
      loginURL: route,
      redirect,
      css: theme,
      lengthLimit,
      optionalFields,
      recaptchaToken: token
        ? { token, action: recaptchaAction }
        : null
    });
  };
  // 🔹 This is the click binding you’re referring to
  bindEvent({ id: buttonId, handler });
}
