// recaptchaToken.js
import { showError } from '../ShowResponse.js';

export const recaptchaToken = async (action = 'SUBMIT') => {
  let token = null;

  if (window.RECAPTCHA_SITE_KEY && window.grecaptcha && window.grecaptcha.enterprise) {
    try {
      token = await window.grecaptcha.enterprise.execute(
        window.RECAPTCHA_SITE_KEY,
        { action }
      );
    } catch (err) {
      showError(err);
    }
  }

  return token;
};
