// createAdminLoginHandler.js
import { id } from '../UtilityHtml.js';
import { bindEvent, showPassword } from '../Utility.js';
import { createFormHandler } from './createFormHandler.js';

export function createAdminLoginHandler({
  formId,
  emailId = 'email',
  passwordId = 'password',
  buttonId = 'button',
  showToggleId = 'showPassword',
  route,
  redirect,
  theme = 'bootstrap',
  recaptchaAction = 'LOGIN',
  lengthLimitArray = null,
  optionalFields = []
}) {
  // Accessibility
  const passwordInput = id(passwordId);
  const toggleLabel = id(showToggleId);

  if (passwordInput) {
    passwordInput.setAttribute('autocomplete', 'current-password');
  }

  if (toggleLabel) {
    toggleLabel.setAttribute(
      'aria-label',
      'Warning: this will display your password on the screen.'
    );
  }

  // Password visibility toggle
  bindEvent({ id: showToggleId, handler: () => showPassword(passwordId) });

  // Core handler
  createFormHandler({
    formId,
    buttonId,
    route,
    redirect,
    theme,
    lengthLimit: lengthLimitArray,
    optionalFields: [emailId, passwordId, ...optionalFields],
    recaptchaAction
  });
}
